+  // ---------- getRevenueByStatus ----------
+
+  describe('getRevenueByStatus', () => {
+    it('should return 200 with revenue breakdown', () => {
+      orderRepo.save(makeOrder({ id: 'o1', total: 100, status: 'pending' }));
+      orderRepo.save(makeOrder({ id: 'o2', total: 200, status: 'shipped' }));
+
+      const res = routes.getRevenueByStatus(req());
+      expect(res.status).toBe(200);
+
+      const body = res.body as Record<string, number>;
+      expect(body.pending).toBe(100);
+      expect(body.shipped).toBe(200);
+      expect(body.delivered).toBe(0);
+    });
+  });
+
+  // ---------- getUserOrderSummary ----------
+
+  describe('getUserOrderSummary', () => {
+    it('should return 400 when userId is missing', () => {
+      const res = routes.getUserOrderSummary(req());
+      expect(res.status).toBe(400);
+      expect(res.body).toEqual({ error: 'Missing required parameter: userId' });
+    });
+
+    it('should return 200 with user order summary', () => {
+      orderRepo.save(makeOrder({ id: 'o1', userId: 'user-1', total: 50 }));
+      orderRepo.save(makeOrder({ id: 'o2', userId: 'user-1', total: 150, status: 'shipped' }));
+      orderRepo.save(makeOrder({ id: 'o3', userId: 'user-2', total: 300 }));
+
+      const res = routes.getUserOrderSummary(req({ params: { userId: 'user-1' } }));
+      expect(res.status).toBe(200);
+
+      const body = res.body as { totalOrders: number; totalSpent: number; averageOrderValue: number };
+      expect(body.totalOrders).toBe(2);
+      expect(body.totalSpent).toBe(200);
+      expect(body.averageOrderValue).toBe(100);
+    });
+
+    it('should return zeroes for unknown user', () => {
+      const res = routes.getUserOrderSummary(req({ params: { userId: 'nonexistent' } }));
+      expect(res.status).toBe(200);
+
+      const body = res.body as { totalOrders: number; totalSpent: number };
+      expect(body.totalOrders).toBe(0);
+      expect(body.totalSpent).toBe(0);
+    });
+  });
+});

