/**
 * Framework-agnostic route handler types.
 *
 * These types define a simple request/response contract so that
 * route handlers remain decoupled from any specific HTTP framework.
 */

/**
 * Incoming request abstraction.
 */
export interface RouteRequest {
  /** Named path parameters (e.g., { userId: "user-0001" }) */
  params: Record<string, string>;
  /** Query string parameters */
  query: Record<string, string | undefined>;
  /** Parsed request body (for POST/PUT/PATCH) */
  body?: unknown;
}

/**
 * Outgoing response abstraction.
 */
export interface RouteResponse {
  /** HTTP status code */
  status: number;
  /** Response body (will be serialized as JSON) */
  body: unknown;
}

/**
 * A route handler function.
 */
export type RouteHandler = (req: RouteRequest) => RouteResponse;

/**
 * Analytics route handlers — connect HTTP-style requests to the
 * AnalyticsService aggregation layer.
 *
 * Each handler validates inputs, calls the service, and returns a
 * typed RouteResponse. No framework dependency — these work with
 * any adapter (Express, Koa, raw Node http, tests, etc.).
 */

import type { TimeGranularity } from '../models/analytics.js';
import type { AnalyticsService } from '../services/analytics.service.js';
import type { RouteRequest, RouteResponse } from './types.js';

const VALID_GRANULARITIES: TimeGranularity[] = ['day', 'week', 'month'];
const DEFAULT_GRANULARITY: TimeGranularity = 'day';
const DEFAULT_TOP_PRODUCTS_LIMIT = 10;
const MAX_TOP_PRODUCTS_LIMIT = 100;

/**
 * Parse and validate a date string from query params.
 * Returns the Date if valid, or an error message string if invalid.
 */
function parseDate(value: string | undefined, label: string): Date | string {
  if (!value) {
    return `Missing required query parameter: ${label}`;
  }
  const date = new Date(value);
  if (isNaN(date.getTime())) {
    return `Invalid date for ${label}: ${value}`;
  }
  return date;
}

/**
 * Parse a granularity query parameter, defaulting to 'day'.
 */
function parseGranularity(value: string | undefined): TimeGranularity | string {
  if (!value) {
    return DEFAULT_GRANULARITY;
  }
  if (!VALID_GRANULARITIES.includes(value as TimeGranularity)) {
    return `Invalid granularity: ${value}. Must be one of: ${VALID_GRANULARITIES.join(', ')}`;
  }
  return value as TimeGranularity;
}

/**
 * Build an error response.
 */
function errorResponse(status: number, message: string): RouteResponse {
  return { status, body: { error: message } };
}

/**
 * Parse the common time-series query parameters (startDate, endDate, granularity).
 * Returns either a valid TimeSeriesQuery or a RouteResponse with the error.
 */
function parseTimeSeriesParams(
  req: RouteRequest,
): { startDate: Date; endDate: Date; granularity: TimeGranularity } | RouteResponse {
  const startResult = parseDate(req.query.startDate, 'startDate');
  if (typeof startResult === 'string') {
    return errorResponse(400, startResult);
  }

  const endResult = parseDate(req.query.endDate, 'endDate');
  if (typeof endResult === 'string') {
    return errorResponse(400, endResult);
  }

  if (startResult > endResult) {
    return errorResponse(400, 'startDate must be before or equal to endDate');
  }

  const granResult = parseGranularity(req.query.granularity);
  if (typeof granResult === 'string' && !VALID_GRANULARITIES.includes(granResult as TimeGranularity)) {
    return errorResponse(400, granResult);
  }

  return {
    startDate: startResult,
    endDate: endResult,
    granularity: granResult as TimeGranularity,
  };
}

function isRouteResponse(value: unknown): value is RouteResponse {
  return typeof value === 'object' && value !== null && 'status' in value && 'body' in value;
}

/**
 * Factory that creates all analytics route handlers bound to an
 * AnalyticsService instance.
 */
export function createAnalyticsRoutes(service: AnalyticsService) {
  return {
    /**
     * GET /analytics/dashboard
     * Query: startDate, endDate, granularity?
     */
    getDashboard(req: RouteRequest): RouteResponse {
      const params = parseTimeSeriesParams(req);
      if (isRouteResponse(params)) return params;

      try {
        const data = service.getDashboardData(params);
        return { status: 200, body: data };
      } catch (err) {
        return errorResponse(500, (err as Error).message);
      }
    },

    /**
     * GET /analytics/orders/summary
     */
    getOrderMetrics(_req: RouteRequest): RouteResponse {
      try {
        const data = service.getOrderMetricSummary();
        return { status: 200, body: data };
      } catch (err) {
        return errorResponse(500, (err as Error).message);
      }
    },

    /**
     * GET /analytics/users/summary
     */
    getUserMetrics(_req: RouteRequest): RouteResponse {
      try {
        const data = service.getUserMetricSummary();
        return { status: 200, body: data };
      } catch (err) {
        return errorResponse(500, (err as Error).message);
      }
    },

    /**
     * GET /analytics/revenue/time-series
     * Query: startDate, endDate, granularity?
     */
    getRevenueTimeSeries(req: RouteRequest): RouteResponse {
      const params = parseTimeSeriesParams(req);
      if (isRouteResponse(params)) return params;

      try {
        const data = service.getRevenueTimeSeries(params);
        return { status: 200, body: data };
      } catch (err) {
        return errorResponse(500, (err as Error).message);
      }
    },

    /**
     * GET /analytics/orders/time-series
     * Query: startDate, endDate, granularity?
     */
    getOrderCountTimeSeries(req: RouteRequest): RouteResponse {
      const params = parseTimeSeriesParams(req);
      if (isRouteResponse(params)) return params;

      try {
        const data = service.getOrderCountTimeSeries(params);
        return { status: 200, body: data };
      } catch (err) {
        return errorResponse(500, (err as Error).message);
      }
    },

    /**
     * GET /analytics/products/top
     * Query: limit? (default 10, max 100)
     */
    getTopProducts(req: RouteRequest): RouteResponse {
      let limit = DEFAULT_TOP_PRODUCTS_LIMIT;

      if (req.query.limit !== undefined) {
        const parsed = Number(req.query.limit);
        if (!Number.isInteger(parsed) || parsed < 1) {
          return errorResponse(400, `Invalid limit: ${req.query.limit}. Must be a positive integer`);
        }
        if (parsed > MAX_TOP_PRODUCTS_LIMIT) {
          return errorResponse(400, `Limit exceeds maximum of ${MAX_TOP_PRODUCTS_LIMIT}`);
        }
        limit = parsed;
      }

      try {
        const data = service.getTopProducts(limit);
        return { status: 200, body: data };
      } catch (err) {
        return errorResponse(500, (err as Error).message);
      }
    },

    /**
     * GET /analytics/revenue/by-status
     */
    getRevenueByStatus(_req: RouteRequest): RouteResponse {
      try {
        const data = service.getRevenueByStatus();
        return { status: 200, body: data };
      } catch (err) {
        return errorResponse(500, (err as Error).message);
      }
    },

    /**
     * GET /analytics/users/:userId/orders
     * Params: userId
     */
    getUserOrderSummary(req: RouteRequest): RouteResponse {
      const { userId } = req.params;

      if (!userId) {
        return errorResponse(400, 'Missing required parameter: userId');
      }

      try {
        const data = service.getUserOrderSummary(userId);
        return { status: 200, body: data };
      } catch (err) {
        return errorResponse(500, (err as Error).message);
      }
    },
  };
}

