import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import { createAnalyticsRoutes } from '../../src/routes/analytics.routes.js';
import type { RouteRequest } from '../../src/routes/types.js';
import type { Order } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';

function makeOrder(overrides: Partial<Order> & { id: string }): Order {
  return {
    userId: 'user-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 25 }],
    total: 50,
    status: 'pending',
    createdAt: new Date('2026-01-15'),
    updatedAt: new Date('2026-01-15'),
    ...overrides,
  };
}

function makeUser(overrides: Partial<User> & { id: string }): User {
  return {
    name: 'Test User',
    email: 'test@example.com',
    role: 'member',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

function req(overrides: Partial<RouteRequest> = {}): RouteRequest {
  return {
    params: {},
    query: {},
    ...overrides,
  };
}

describe('Analytics Routes', () => {
  let db: Database;
  let orderRepo: OrderRepository;
  let userRepo: UserRepository;
  let service: AnalyticsService;
  let routes: ReturnType<typeof createAnalyticsRoutes>;

  beforeEach(() => {
    db = new Database();
    orderRepo = new OrderRepository(db);
    userRepo = new UserRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
    routes = createAnalyticsRoutes(service);
  });

  // ---------- getDashboard ----------

  describe('getDashboard', () => {
    it('should return 400 when startDate is missing', () => {
      const res = routes.getDashboard(req({ query: { endDate: '2026-01-31' } }));
      expect(res.status).toBe(400);
      expect(res.body).toEqual({ error: 'Missing required query parameter: startDate' });
    });

    it('should return 400 when endDate is missing', () => {
      const res = routes.getDashboard(req({ query: { startDate: '2026-01-01' } }));
      expect(res.status).toBe(400);
      expect(res.body).toEqual({ error: 'Missing required query parameter: endDate' });
    });

    it('should return 400 for invalid date', () => {
      const res = routes.getDashboard(req({ query: { startDate: 'not-a-date', endDate: '2026-01-31' } }));
      expect(res.status).toBe(400);
      expect((res.body as { error: string }).error).toContain('Invalid date');
    });

    it('should return 400 when startDate is after endDate', () => {
      const res = routes.getDashboard(req({ query: { startDate: '2026-02-01', endDate: '2026-01-01' } }));
      expect(res.status).toBe(400);
      expect(res.body).toEqual({ error: 'startDate must be before or equal to endDate' });
    });

    it('should return 400 for invalid granularity', () => {
      const res = routes.getDashboard(req({
        query: { startDate: '2026-01-01', endDate: '2026-01-31', granularity: 'year' },
      }));
      expect(res.status).toBe(400);
      expect((res.body as { error: string }).error).toContain('Invalid granularity');
    });

    it('should return 200 with dashboard data', () => {
      orderRepo.save(makeOrder({ id: 'o1' }));
      userRepo.save(makeUser({ id: 'u1' }));

      const res = routes.getDashboard(req({
        query: { startDate: '2026-01-01', endDate: '2026-01-31', granularity: 'day' },
      }));

      expect(res.status).toBe(200);
      const body = res.body as Record<string, unknown>;
      expect(body).toHaveProperty('orderMetrics');
      expect(body).toHaveProperty('userMetrics');
      expect(body).toHaveProperty('revenueTimeSeries');
      expect(body).toHaveProperty('ordersTimeSeries');
      expect(body).toHaveProperty('topProducts');
      expect(body).toHaveProperty('generatedAt');
    });

    it('should default granularity to day when not specified', () => {
      const res = routes.getDashboard(req({
        query: { startDate: '2026-01-01', endDate: '2026-01-03' },
      }));

      expect(res.status).toBe(200);
      const body = res.body as { revenueTimeSeries: { granularity: string } };
      expect(body.revenueTimeSeries.granularity).toBe('day');
    });
  });

  // ---------- getOrderMetrics ----------

  describe('getOrderMetrics', () => {
    it('should return 200 with order metrics for empty data', () => {
      const res = routes.getOrderMetrics(req());
      expect(res.status).toBe(200);

      const body = res.body as Record<string, unknown>;
      expect(body).toHaveProperty('totalOrders', 0);
      expect(body).toHaveProperty('totalRevenue', 0);
      expect(body).toHaveProperty('averageOrderValue', 0);
    });

    it('should return correct metrics with data', () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 100 }));
      orderRepo.save(makeOrder({ id: 'o2', total: 200, status: 'shipped' }));

      const res = routes.getOrderMetrics(req());
      expect(res.status).toBe(200);

      const body = res.body as { totalOrders: number; totalRevenue: number; averageOrderValue: number };
      expect(body.totalOrders).toBe(2);
      expect(body.totalRevenue).toBe(300);
      expect(body.averageOrderValue).toBe(150);
    });
  });

  // ---------- getUserMetrics ----------

  describe('getUserMetrics', () => {
    it('should return 200 with user metrics', () => {
      userRepo.save(makeUser({ id: 'u1', role: 'admin' }));
      userRepo.save(makeUser({ id: 'u2', email: 'two@example.com', role: 'member' }));

      const res = routes.getUserMetrics(req());
      expect(res.status).toBe(200);

      const body = res.body as { totalUsers: number; usersByRole: Record<string, number> };
      expect(body.totalUsers).toBe(2);
      expect(body.usersByRole.admin).toBe(1);
      expect(body.usersByRole.member).toBe(1);
    });
  });

  // ---------- getRevenueTimeSeries ----------

  describe('getRevenueTimeSeries', () => {
    it('should return 400 for missing dates', () => {
      const res = routes.getRevenueTimeSeries(req());
      expect(res.status).toBe(400);
    });

    it('should return 200 with time-series data', () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 100, createdAt: new Date('2026-01-15') }));

      const res = routes.getRevenueTimeSeries(req({
        query: { startDate: '2026-01-01', endDate: '2026-01-31', granularity: 'month' },
      }));

      expect(res.status).toBe(200);
      const body = res.body as { metric: string; data: Array<{ date: string; value: number }> };
      expect(body.metric).toBe('revenue');
      expect(body.data.length).toBeGreaterThan(0);
    });
  });

  // ---------- getOrderCountTimeSeries ----------

  describe('getOrderCountTimeSeries', () => {
    it('should return 400 for missing dates', () => {
      const res = routes.getOrderCountTimeSeries(req());
      expect(res.status).toBe(400);
    });

    it('should return 200 with order counts', () => {
      orderRepo.save(makeOrder({ id: 'o1', createdAt: new Date('2026-01-10') }));
      orderRepo.save(makeOrder({ id: 'o2', createdAt: new Date('2026-01-10') }));

      const res = routes.getOrderCountTimeSeries(req({
        query: { startDate: '2026-01-01', endDate: '2026-01-31', granularity: 'day' },
      }));

      expect(res.status).toBe(200);
      const body = res.body as { metric: string; data: Array<{ date: string; value: number }> };
      expect(body.metric).toBe('orders');
      const jan10 = body.data.find(d => d.date === '2026-01-10');
      expect(jan10?.value).toBe(2);
    });
  });

  // ---------- getTopProducts ----------

  describe('getTopProducts', () => {
    it('should return 200 with default limit', () => {
      const res = routes.getTopProducts(req());
      expect(res.status).toBe(200);
      expect(Array.isArray(res.body)).toBe(true);
    });

    it('should respect custom limit', () => {
      for (let i = 0; i < 5; i++) {
        orderRepo.save(makeOrder({
          id: `o${i}`,
          items: [{ productId: `p${i}`, name: `Product ${i}`, quantity: 1, unitPrice: 10 }],
        }));
      }

      const res = routes.getTopProducts(req({ query: { limit: '3' } }));
      expect(res.status).toBe(200);
      expect((res.body as unknown[]).length).toBe(3);
    });

    it('should return 400 for invalid limit', () => {
      const res = routes.getTopProducts(req({ query: { limit: 'abc' } }));
      expect(res.status).toBe(400);
      expect((res.body as { error: string }).error).toContain('Invalid limit');
    });

    it('should return 400 for limit of 0', () => {
      const res = routes.getTopProducts(req({ query: { limit: '0' } }));
      expect(res.status).toBe(400);
    });

    it('should return 400 for limit exceeding max', () => {
      const res = routes.getTopProducts(req({ query: { limit: '101' } }));
      expect(res.status).toBe(400);
      expect((res.body as { error: string }).error).toContain('maximum');
    });
  });

  // ---------- getRevenueByStatus ----------

  describe('getRevenueByStatus', () => {
    it('should return 200 with revenue breakdown', () => {
      orderRepo.save(makeOrder({ id: 'o1', total: 100, status: 'pending' }));
      orderRepo.save(makeOrder({ id: 'o2', total: 200, status: 'shipped' }));

      const res = routes.getRevenueByStatus(req());
      expect(res.status).toBe(200);

      const body = res.body as Record<string, number>;
      expect(body.pending).toBe(100);
      expect(body.shipped).toBe(200);
      expect(body.delivered).toBe(0);
    });
  });

  // ---------- getUserOrderSummary ----------

  describe('getUserOrderSummary', () => {
    it('should return 400 when userId is missing', () => {
      const res = routes.getUserOrderSummary(req());
      expect(res.status).toBe(400);
      expect(res.body).toEqual({ error: 'Missing required parameter: userId' });
    });

    it('should return 200 with user order summary', () => {
      orderRepo.save(makeOrder({ id: 'o1', userId: 'user-1', total: 50 }));
      orderRepo.save(makeOrder({ id: 'o2', userId: 'user-1', total: 150, status: 'shipped' }));
      orderRepo.save(makeOrder({ id: 'o3', userId: 'user-2', total: 300 }));

      const res = routes.getUserOrderSummary(req({ params: { userId: 'user-1' } }));
      expect(res.status).toBe(200);

      const body = res.body as { totalOrders: number; totalSpent: number; averageOrderValue: number };
      expect(body.totalOrders).toBe(2);
      expect(body.totalSpent).toBe(200);
      expect(body.averageOrderValue).toBe(100);
    });

    it('should return zeroes for unknown user', () => {
      const res = routes.getUserOrderSummary(req({ params: { userId: 'nonexistent' } }));
      expect(res.status).toBe(200);

      const body = res.body as { totalOrders: number; totalSpent: number };
      expect(body.totalOrders).toBe(0);
      expect(body.totalSpent).toBe(0);
    });
  });
});
